const $ = require('jquery');
const _ = require('lodash');

const CONSOLE = require('./console');

const XHR = {
    /**
     * @memberof BXUI.Xhr
     */
    "ajax": _ajax,
    /**
     * @memberof BXUI.Xhr
     */
    "get": _get,
    /**
     * @memberof BXUI.Xhr
     */
    "post": _post,
    /**
     * @memberof BXUI.Xhr
     */
    "isSupportedXHR2": _isSupportedXHR2
};

const MESSAGES = {
    "noSupportedUploadType": '해당 브라우저는 `upload` 타입을 지원하지 않습니다',
    "noSupportedBinary": '해당 브라우저는 `binary` 타입을 지원하지 않습니다'
};


/**
 * XHR level2 를 대응하기위한, get 메서드
 *
 * @param {Object} [opts] - ajax options
 * @param {String} [opts.transferType] - 데이터 전송 타입(download, upload)
 * @param {String} [opts.loadStart] - xhr level2 loadStart event
 * @param {String} [opts.progress] - xhr level2 progress event
 * @param {String} [opts.xhrFields] - 별도 xhr option 을 정의하기위한 속성
 *
 * @return {object} jq jqxhr 객체
 */
function _ajax(opts){

    if (!_.isPlainObject(opts)){
        CONSOLE.prop.throw('BXUI.Xhr.ajax', 'opts', 'type');
    }

    opts = _ajaxSetup.call(this, opts);

    return $.ajax(opts);
}

/**
 * XHR level2 를 대응하기위한, jq get 확장 메서드
 *
 * @param {Object} [opts] - ajax options
 * @param {String} [opts.transferType] - 데이터 전송 타입(download, upload)
 * @param {String} [opts.loadStart] - xhr level2 loadStart event
 * @param {String} [opts.progress] - xhr level2 progress event
 * @param {String} [opts.xhrFields] - 별도 xhr option 을 정의하기위한 속성
 *
 * @return {object} jq jqxhr 객체
 */
function _get(opts){

    if (!_.isPlainObject(opts)){
        CONSOLE.prop.throw('BXUI.Xhr.get', 'opts', 'type');
    }

    opts = _ajaxSetup.call(this, opts);

    opts.type = 'get';

    return $.ajax(opts);
}

/**
 * XHR level2 를 대응하기위한, post 메서드
 *
 * @param {Object} [opts] - ajax options
 * @param {String} [opts.transferType] - 데이터 전송 타입(download, upload)
 * @param {String} [opts.loadStart] - xhr level2 loadStart event
 * @param {String} [opts.progress] - xhr level2 progress event
 * @param {String} [opts.xhrFields] - 별도 xhr option 을 정의하기위한 속성
 *
 * @return {object} jq jqxhr 객체
 */
function _post(opts){

    if (!_.isPlainObject(opts)){
        CONSOLE.prop.throw('BXUI.Xhr.post', 'opts', 'type');
    }

    opts = _ajaxSetup.call(this, opts);

    opts.type = 'post';

    return $.ajax(opts);
}

/**
 * XHR 설정을 초기화한다.
 *
 * @param {Object} [opts] - ajax options
 * @param {String} [opts.transferType] - 데이터 전송 타입(download, upload)
 * @param {String} [opts.loadStart] - xhr level2 loadStart event
 * @param {String} [opts.progress] - xhr level2 progress event
 * @param {String} [opts.xhrFields] - 별도 xhr option 을 정의하기위한 속성
 *
 * @return {object} 설정된 opts 객체
 */
function _ajaxSetup(opts){

    if (!_.isPlainObject(opts)){
        CONSOLE.prop.throw('BXUI.Xhr.ajaxSetup', 'opts', 'type');
    }

    let defaultOpts = {
        "transferType": 'download',
        "loadStart": function(){},
        "progress": function(){},
        "xhrFields": {}
    };

    opts = _.assign(defaultOpts, opts);

    let isSupportedXHR2 = this.isSupportedXHR2();

    if (!isSupportedXHR2 && opts.transferType === 'upload'){
        CONSOLE.prop.throw('BXUI.Xhr.ajaxSetup', MESSAGES.noSupportedUploadType);
    }

    if (!isSupportedXHR2 && opts.dataType === 'binary'){
        CONSOLE.prop.throw('BXUI.Xhr.ajaxSetup', MESSAGES.noSupportedBinary);
    }

    if (opts.dataType === 'binary'){
        opts.xhrFields.responseType = opts.xhrFields.responseType || 'blob';
    }

    opts.xhr = () => {

        let xhr = $.ajaxSettings.xhr();

        // xhr level2 를 지원하는 브라우저일 경우
        if (isSupportedXHR2){

            let bindingObject = opts.transferType === 'download' ? xhr : xhr.upload;

            bindingObject.addEventListener('loadstart', e => {
                opts.loadStart.call(null, xhr);
            }, false);

            bindingObject.addEventListener('progress', e => {

                if (e.lengthComputable) {

                    let percent = (e.loaded / e.total * 100).toFixed(0);

                    opts.progress.apply(null, [xhr, e.loaded, e.total, percent]);
                }
            }, false);
        }

        return xhr;
    };

    return opts;
}

/**
 * xhr level2 지원 여부를 반환한다.
 *
 * @return {Boolean} 지원 여부
 *
 */
function _isSupportedXHR2(){

    let ret = false;

    if (window.ProgressEvent && window.FormData){
        ret = true;
    }

    return ret;
}

module.exports = XHR;